<?php if(!hasPermission('sales_update')){http_response_code(403); include __DIR__.'/../errors/403.php'; return;} $db=Database::connection(); $id=(int)($segments[2]??0); if($_SERVER['REQUEST_METHOD']==='POST'){ $amt=(float)$_POST['amount']; $db->beginTransaction(); try{$db->prepare('INSERT INTO payments (payment_date,party_type,party_id,payment_mode,amount,reference_no,narration,created_by,created_at) SELECT CURDATE(),\'customer\',customer_id,?,?,?, ?,?,NOW() FROM sales_invoices WHERE id=?')->execute([$_POST['payment_mode'],$amt,$_POST['reference_no']??'',$_POST['narration']??'',getCurrentUser()['id']??null,$id]); $db->prepare('UPDATE sales_invoices SET paid_amount=paid_amount+?, balance_amount=GREATEST(0,balance_amount-?), payment_status=CASE WHEN balance_amount-?<=0 THEN "paid" ELSE "partial" END WHERE id=?')->execute([$amt,$amt,$amt,$id]);$db->commit();redirect('sales/view/'.$id);}catch(Throwable $e){$db->rollBack();}}?><form method='post'><?=csrfField()?> <input name='amount'><select name='payment_mode'><option>cash</option><option>bank</option></select><button>Save Payment</button></form>
